"use client"

import { useEffect, useState } from "react"
import { useRouter } from "next/navigation"
import { LoginForm } from "@/components/login-form"
import { Package2 } from "lucide-react"

export default function LoginPage() {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)

  useEffect(() => {
    const token = localStorage.getItem("token")
    if (token) {
      router.push("/dashboard")
    }
  }, [router])

  const handleLoginSuccess = (token: string, userData: { id: number; name: string; email: string }) => {
    setIsLoading(true)
    localStorage.setItem("token", token)
    localStorage.setItem("user", JSON.stringify(userData))
    router.push("/dashboard")
  }

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <header className="absolute top-0 left-0 right-0 flex items-center justify-between px-6 py-6 md:px-12 text-xs md:text-sm text-slate-400">
        <a href="/" className="hover:text-slate-200 transition-colors duration-200 uppercase tracking-wide">
          Contact
        </a>
        <div className="absolute left-1/2 -translate-x-1/2">
          <Package2 className="w-7 h-7 text-slate-300 hover:text-slate-100 transition-colors cursor-pointer" />
        </div>
        <a href="/" className="hover:text-slate-200 transition-colors duration-200 uppercase tracking-wide">
          Theme Marketplace
        </a>
      </header>

      <div className="w-full max-w-lg bg-slate-800 p-8 rounded-lg shadow-lg flex flex-col items-start">
        {/* Título */}
        <div className="text-center mb-12">
          <h1 className="text-4xl font-light text-slate-100 uppercase tracking-[0.15em]">Asistente Financiero</h1>
          <p className="text-sm text-slate-400">Ingresa tus credenciales para acceder a tu dashboard</p>
        </div>

        {/* Colocar el formulario a la izquierda */}
        <div className="w-full max-w-md">
          <LoginForm onSuccess={handleLoginSuccess} />

          {/* Indicador de carga */}
          {isLoading && (
            <div className="mt-6 flex justify-center">
              <div className="animate-spin rounded-full h-8 w-8 border-2 border-slate-600 border-t-emerald-500"></div>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}
